import{_ as n,o as s,c as a,ag as t}from"./chunks/framework.DAvaMl8U.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),o={name:"architecture.md"};function c(r,e,p,i,l,d){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">вҖӢ</a></h1><p>Incharj has one job: connect to external knowledge sources, index their content, and make it searchable. Everything in the codebase exists to serve that loop.</p><hr><h2 id="the-core-loop" tabindex="-1">The core loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The core loop&quot;">вҖӢ</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>External source          Worker process              PostgreSQL</span></span>
<span class="line"><span>(Google Drive,    в”Җв”Җв–ә   Connector                  в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ</span></span>
<span class="line"><span> Notion, Slack)         listDocuments()  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв–әв”Ӯ connectors      в”Ӯ</span></span>
<span class="line"><span>                        fetchContent()              в”Ӯ sync_jobs       в”Ӯ</span></span>
<span class="line"><span>                              в”Ӯ                     в”Ӯ documents       в”Ӯ</span></span>
<span class="line"><span>                              в–ј                     в”Ӯ document_chunks в”Ӯ</span></span>
<span class="line"><span>                         Indexer                    в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span>
<span class="line"><span>                         ingestDocument()                    в”Ӯ</span></span>
<span class="line"><span>                              в”Ӯ                             GIN</span></span>
<span class="line"><span>                              в””в”Җв”Җв”Җв”Җ search_vector в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв–әв”Ӯ</span></span>
<span class="line"><span>                                    (pre-computed)           в”Ӯ</span></span>
<span class="line"><span>                                                   в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв–јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ</span></span>
<span class="line"><span>                                    API в—„в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Ӯ  Search engine   в”Ӯ</span></span>
<span class="line"><span>                                    query          в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span></code></pre></div><p>Three processes share the same PostgreSQL database:</p><table tabindex="0"><thead><tr><th>Process</th><th>Role</th></tr></thead><tbody><tr><td><strong>API</strong> (Fastify)</td><td>Handles HTTP requests вҖ” auth, connectors, search, documents</td></tr><tr><td><strong>Worker</strong> (BullMQ)</td><td>Runs sync jobs вҖ” fetches, indexes, updates search vectors</td></tr><tr><td><strong>Redis</strong></td><td>Job queue only вҖ” BullMQ stores pending and running sync jobs</td></tr></tbody></table><hr><h2 id="how-a-sync-happens" tabindex="-1">How a sync happens <a class="header-anchor" href="#how-a-sync-happens" aria-label="Permalink to &quot;How a sync happens&quot;">вҖӢ</a></h2><p>A <strong>dispatch job</strong> runs every 30 seconds and finds connectors where <code>last_synced_at + sync_frequency &lt; now()</code>. For each due connector it creates a <code>sync_jobs</code> row (status = <code>pending</code>) and enqueues a <code>&quot;sync&quot;</code> job to Redis.</p><p>The <strong>sync worker</strong> (concurrency = 1) picks up the job and calls <code>runSync()</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Decrypt OAuth credentials (AES-GCM)</span></span>
<span class="line"><span>2. Refresh access token if expired</span></span>
<span class="line"><span>3. connector.listDocuments()  вҶҗ async generator, incremental via last_synced_at</span></span>
<span class="line"><span>4. for each doc:</span></span>
<span class="line"><span>     connector.fetchContent()</span></span>
<span class="line"><span>     ingestDocument()          вҶҗ own transaction, failure is isolated</span></span>
<span class="line"><span>5. Update connectors.doc_count + last_synced_at</span></span></code></pre></div><p>See <a href="./indexer">Indexer</a> for what happens inside <code>ingestDocument()</code>.</p><hr><h2 id="how-a-search-happens" tabindex="-1">How a search happens <a class="header-anchor" href="#how-a-search-happens" aria-label="Permalink to &quot;How a search happens&quot;">вҖӢ</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser вҶ’ GET /orgs/:slug/search?q=product+roadmap</span></span>
<span class="line"><span>              в”Ӯ</span></span>
<span class="line"><span>              в–ј</span></span>
<span class="line"><span>         Stop word check  вҶҗ websearch_to_tsquery empty? вҶ’ return [] immediately</span></span>
<span class="line"><span>              в”Ӯ</span></span>
<span class="line"><span>              в–ј</span></span>
<span class="line"><span>         FTS query        вҶҗ search_vector @@ tsq  (GIN index, no table scan)</span></span>
<span class="line"><span>              в”Ӯ</span></span>
<span class="line"><span>         total &gt; 0? в”Җв”Җyesв”Җв”Җв–ә rank + snippet вҶ’ return</span></span>
<span class="line"><span>              в”Ӯ</span></span>
<span class="line"><span>             no</span></span>
<span class="line"><span>              в–ј</span></span>
<span class="line"><span>         Fuzzy query      вҶҗ similarity(title, q) &gt; 0.1  (GIN trgm index)</span></span>
<span class="line"><span>              в”Ӯ</span></span>
<span class="line"><span>              в–ј</span></span>
<span class="line"><span>         return results</span></span></code></pre></div><p>See <a href="./search">Search</a> for the full ranking formula and scoring details.</p><hr><h2 id="multi-tenancy" tabindex="-1">Multi-tenancy <a class="header-anchor" href="#multi-tenancy" aria-label="Permalink to &quot;Multi-tenancy&quot;">вҖӢ</a></h2><p>Every table that holds user data carries an <code>org_id</code> column. All queries вҖ” search, documents, connectors вҖ” are filtered by <code>org_id</code> before anything else. The API middleware resolves the org from the URL slug and verifies the caller is a member before allowing any data access.</p><hr><h2 id="key-constraints-that-shaped-the-design" tabindex="-1">Key constraints that shaped the design <a class="header-anchor" href="#key-constraints-that-shaped-the-design" aria-label="Permalink to &quot;Key constraints that shaped the design&quot;">вҖӢ</a></h2><p><strong>Pre-computed search vectors</strong> вҖ” <code>to_tsvector()</code> is called at index time, not query time. Two GIN indexes (<code>ix_documents_search_vector</code>, <code>ix_chunks_search_vector</code>) let the search query skip the tokenisation step entirely.</p><p><strong>Per-document transactions</strong> вҖ” each call to <code>ingestDocument()</code> runs in its own <code>BEGIN / COMMIT</code>. A malformed PDF or a network hiccup on one document is counted as <code>docs_errored</code> and the sync continues.</p><p><strong>Incremental sync at the source</strong> вҖ” connectors filter changed documents using the source API&#39;s own query parameters (e.g. Google Drive <code>modifiedTime &gt;</code>). Only genuinely new or changed documents reach the indexer.</p><p><strong>Content hash includes title</strong> вҖ” <code>SHA-256(title::content)</code> means a rename with no body change still triggers re-index. Without the title in the hash, renames would be silently ignored.</p>`,26)])])}const g=n(o,[["render",c]]);export{u as __pageData,g as default};
